UPDATE hordes
SET target_pace = CASE id
    WHEN '11111111-1111-1111-1111-111111111111' THEN 8.0
    WHEN '22222222-2222-2222-2222-222222222222' THEN 6.0
    WHEN '33333333-3333-3333-3333-333333333333' THEN 4.0
END
WHERE id IN (
    '11111111-1111-1111-1111-111111111111',
    '22222222-2222-2222-2222-222222222222',
    '33333333-3333-3333-3333-333333333333'
);
